#include <common/kprint.h>
#include <common/types.h>
#include <common/vars.h>
#include <mm/mm.h>
#include <irq/irq.h>
#include <sched/sched.h>
#include <sched/fpu.h>
#include <object/thread.h>
#include <machine.h>
#include <arch/mmu.h>
#include <arch/plic.h>
#include <arch/machine/smp.h>
#include <arch/machine/pmu.h>
#include <arch/machine/sbi.h>
#include <arch/drivers/devicetree/fdt.h>

/* Global big kernel lock */
struct lock big_kernel_lock;

ALIGN(STACK_ALIGNMENT)
char cpu_stacks[PLAT_CPU_NUM][CPU_STACK_SIZE];

void run_test(void);

void main(u64 hardware_cpuid, u64 fdt_addr)
{
	u64 ret = 0;

	init_per_cpu_info(hardware_cpuid);
	kinfo("[ChCore] per cpu info init finished\n");

	parse_fdt((u32)fdt_addr);
	kinfo("[ChCore] parse flattened device tree finished\n");

	arch_interrupt_init();
	timer_init();
	kinfo("[ChCore] interrupt init finished\n");

	/* Configure u-mode's accessbility to PMU. */
	pmu_init();
	kinfo("[ChCore] pmu init finished\n");

	mm_init(fdt_get_mem_info());
	kinfo("[ChCore] mm init finished\n");

	/* Configure CPU features: setting per_core registers */
	arch_cpu_init();

	plic_init_per_hart();
	plic_init();
	kinfo("[ChCore] plic init finished\n");

	ret = lock_init(&big_kernel_lock);
	kinfo("[ChCore] lock init finished\n");
	BUG_ON(ret != 0);

#if defined(CHCORE_KERNEL_SCHED_PBFIFO)
	sched_init(&pbfifo);
#elif defined(CHCORE_KERNEL_RT)
	sched_init(&pbrr);
#else
	sched_init(&rr);
#endif
	kinfo("[ChCore] sched init finished\n");

	enable_smp_cores();
	kinfo("[ChCore] enable smp finished\n");

#if FPU_SAVING_MODE == LAZY_FPU_MODE
	disable_fpu_usage();
#endif

#ifdef CHCORE_KERNEL_TEST
	kinfo("[ChCore] kernel tests start\n");
	run_test();
	kinfo("ChCore] kernel tests done\n");
#endif /* CHCORE_KERNEL_TEST */

	create_root_thread();
	kinfo("[ChCore] create initial thread done\n");

	sched();
	eret_to_thread(switch_context());
	BUG("[FATAL] should never be here\n");
}

void secondary_start(u64 hardware_cpuid, u64 fdt_addr)
{
	arch_interrupt_init_per_cpu();

	init_per_cpu_info(hardware_cpuid);

#ifdef CHCORE_KERNEL_TEST
	run_test();
#endif /* CHCORE_KERNEL_TEST */

	timer_init();
	pmu_init();
	arch_cpu_init();
	plic_init_per_hart();

#if FPU_SAVING_MODE == LAZY_FPU_MODE
	disable_fpu_usage();
#endif

	sched();
	eret_to_thread(switch_context());
}

