typedef unsigned long u64;
typedef unsigned int u32;

#include <common/vars.h>

#define PAGE_SHIFT  12
#define PAGE_ORDER  9
/* The number of entries in one page table page. */
#define PTP_ENTRIES 512
/* The size of one page table page. */
#define PTP_SIZE    4096

/* PTE attributes. */
#define PTE_V   (1L << 0)
#define PTE_R   (1L << 1)
#define PTE_W   (1L << 2)
#define PTE_X   (1L << 3)
#define PTE_U   (1L << 4)
#define PTE_G   (1L << 5)
#define PTE_A   (1L << 6)
#define PTE_D   (1L << 7)

#define PTP_INDEX_MASK     ((1 << PAGE_ORDER) - 1)
#define L0_INDEX_SHIFT     ((3 * PAGE_ORDER) + PAGE_SHIFT)
#define L1_INDEX_SHIFT     ((2 * PAGE_ORDER) + PAGE_SHIFT)
#define L2_INDEX_SHIFT     ((1 * PAGE_ORDER) + PAGE_SHIFT)
#define L3_INDEX_SHIFT     ((0 * PAGE_ORDER) + PAGE_SHIFT)
#define GET_L0_INDEX(addr) (((addr) >> L0_INDEX_SHIFT) & PTP_INDEX_MASK)
#define GET_L1_INDEX(addr) (((addr) >> L1_INDEX_SHIFT) & PTP_INDEX_MASK)
#define GET_L2_INDEX(addr) (((addr) >> L2_INDEX_SHIFT) & PTP_INDEX_MASK)
#define GET_L3_INDEX(addr) (((addr) >> L3_INDEX_SHIFT) & PTP_INDEX_MASK)

/* Physical address -> physical page number. */
#define PA2PPN1G(pa) (((u64)pa >> 30))
#define PA2PPN2M(pa) (((u64)pa >> 21))
#define PA2PPN4K(pa) (((u64)pa >> 12))

#define SATP_SV39 (8UL << 60)
#define SATP_SV48 (9UL << 60)

#define SV48_PTE_PPN0_OFFSET 10
#define SV48_PTE_PPN1_OFFSET 19
#define SV48_PTE_PPN2_OFFSET 28
#define SV48_PTE_PPN3_OFFSET 37

/*
 * RV64 SATP (Supervisor Address Translation and Protection Register)
 * [0  ~ 43]: PPN (Physical Page Number)
 * [44 ~ 59]: ASID
 * [60 ~ 63]: Mode (SV39 or SV48)
 */
/* Note: ASID is zero. */
#define MAKE_SATP(mode, pagetable) (mode | (((u64)pagetable) >> 12))

/*
 * Note that MMU is not enabled during the execution of init_boot_pt(),
 * so we need to make sure that every memory access is physical memory
 * access. We use the macro below to meet this requirement.
 *
 * Further detail: C code compiled with -fPIC option will use GOT for addressing.
 * And each GOT entry stores high address of corresponding symbol. So we have to
 * subtract symbol's address from KBASE to get symbol's low address.
 */
#define POINTER_USING_PADDR(type, addr) ((type *)(PADDR((u64)addr)))

#define QEMU_VIRT_START_PADDR 0x80000000
#define PLIC_BASE_ADDR 0xC000000


#ifdef SV48
#define PADDR(x)	((u64)(x) - KBASE)

#define ALIGN(n) __attribute__((__aligned__(n)))
u64 boot_satp_l0[PTP_ENTRIES] ALIGN(PTP_SIZE);
u64 boot_satp_l1_down[PTP_ENTRIES] ALIGN(PTP_SIZE);
u64 boot_satp_l1_up[PTP_ENTRIES] ALIGN(PTP_SIZE);
u64 boot_satp;
/*
 * Currently ChCore use SV48.
 * TODO: Add an macro to switch between SV39 and SV48 ?
 */
void init_boot_pt(void)
{
	u32 idx;
	u32 start_pte_idx;
	u32 end_pte_idx;
	u64 start_physical_page_num;

        // clang-format off
        /*
         * Map virtual address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G
         * to physical address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G with rwx.
         */
        POINTER_USING_PADDR(u64, boot_satp_l0)[0] =
                (PADDR(boot_satp_l1_down) >> (PAGE_SHIFT - SV48_PTE_PPN0_OFFSET)) | PTE_V | PTE_G;
        start_physical_page_num = PA2PPN1G(QEMU_VIRT_START_PADDR);
        start_pte_idx = GET_L1_INDEX(QEMU_VIRT_START_PADDR);
        end_pte_idx = start_pte_idx + 4;
        for (idx = start_pte_idx; idx < end_pte_idx; ++idx) {
                POINTER_USING_PADDR(u64, boot_satp_l1_down)[idx] = ((start_physical_page_num++) << SV48_PTE_PPN2_OFFSET)
                        | PTE_V
                        | PTE_R
                        | PTE_W
                        | PTE_X
                        | PTE_G
                        | PTE_A
                        | PTE_D;
        }
        // clang-format on

        /* Map virtual address 1 ~ 2G to physical address 1 ~ 2G for PLIC MMIO with rw. */
	start_physical_page_num = PA2PPN1G(PLIC_BASE_ADDR);
	start_pte_idx = GET_L1_INDEX(PLIC_BASE_ADDR);
	POINTER_USING_PADDR(u64, boot_satp_l1_down)[start_pte_idx] = ((start_physical_page_num) << SV48_PTE_PPN2_OFFSET)
			| PTE_V
			| PTE_R
			| PTE_W
			| PTE_G
			| PTE_A
			| PTE_D;

	/*
	 * Map virtual address QEMU_VIRT_START_PADDR + KBASE ~ QEMU_VIRT_START_PADDR + 4G
	 * to physical address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G with rwx.
	 */
	POINTER_USING_PADDR(u64, boot_satp_l0)[GET_L0_INDEX(KBASE)] =
                (PADDR(boot_satp_l1_up) >> (PAGE_SHIFT - SV48_PTE_PPN0_OFFSET)) | PTE_V | PTE_G;
	start_physical_page_num = PA2PPN1G(QEMU_VIRT_START_PADDR);
	start_pte_idx = GET_L1_INDEX(QEMU_VIRT_START_PADDR + KBASE);
	end_pte_idx = start_pte_idx + 4;
	for (idx = start_pte_idx; idx < end_pte_idx; ++idx) {
		POINTER_USING_PADDR(u64, boot_satp_l1_up)[idx] = ((start_physical_page_num++) << SV48_PTE_PPN2_OFFSET)
			| PTE_V
			| PTE_R
			| PTE_W
			| PTE_X
			| PTE_G
			| PTE_A
			| PTE_D;
	}

	/* Map virtual address 1 ~ 2G + KBASE to physical address 1 ~ 2G for PLIC MMIO with rw. */
	start_physical_page_num = PA2PPN1G(PLIC_BASE_ADDR);
	start_pte_idx = GET_L1_INDEX(PLIC_BASE_ADDR + KBASE);
	POINTER_USING_PADDR(u64, boot_satp_l1_up)[start_pte_idx] = ((start_physical_page_num) << SV48_PTE_PPN2_OFFSET)
			| PTE_V
			| PTE_R
			| PTE_W
			| PTE_G
			| PTE_A
			| PTE_D;

	*POINTER_USING_PADDR(u64, &boot_satp) = MAKE_SATP(SATP_SV48, PADDR(boot_satp_l0));
}

#elif defined(SV39)
#define PADDR(x)	((u64)(x) - KBASE)
#define SV39_PTE_PPN2_OFFSET 28

#define ALIGN(n) __attribute__((__aligned__(n)))
u64 boot_satp_l0[PTP_ENTRIES] ALIGN(PTP_SIZE);
u64 boot_satp;

void init_boot_pt(void)
{
	u32 idx;
	u32 start_pte_idx;
	u32 end_pte_idx;
	u64 start_physical_page_num;

	/* Map kernel space by 1G page. boot_satp_l0 is l0_ptp */
	/*
	 * Map virtual address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G
	 * to physical address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G.
	 */
	start_physical_page_num = PA2PPN1G(QEMU_VIRT_START_PADDR);
	start_pte_idx = GET_L1_INDEX(QEMU_VIRT_START_PADDR);
	end_pte_idx = start_pte_idx + 4;
	for (idx = start_pte_idx; idx < end_pte_idx; ++idx) {
		POINTER_USING_PADDR(u64, boot_satp_l0)[idx] = ((start_physical_page_num++) << SV39_PTE_PPN2_OFFSET)
			| PTE_V
			| PTE_R
			| PTE_W
			| PTE_X
			| PTE_G
			| PTE_A
			| PTE_D;
	}

	/* Map virtual address 1 ~ 2G to physical address 1 ~ 2G for PLIC MMIO with rw. */
	start_physical_page_num = PA2PPN1G(PLIC_BASE_ADDR);
	start_pte_idx = GET_L1_INDEX(PLIC_BASE_ADDR);
	POINTER_USING_PADDR(u64, boot_satp_l0)[start_pte_idx] = ((start_physical_page_num) << SV39_PTE_PPN2_OFFSET)
			| PTE_V
	    	| PTE_R
			| PTE_W
			| PTE_G
			| PTE_A
			| PTE_D;

	/* Map virtual address 1 ~ 2G to physical address 1 ~ 2G for PLIC MMIO with rw. */
	start_physical_page_num = PA2PPN1G(PLIC_BASE_ADDR);
	start_pte_idx = GET_L1_INDEX(PLIC_BASE_ADDR + KBASE);
	POINTER_USING_PADDR(u64, boot_satp_l0)[start_pte_idx] = ((start_physical_page_num) << SV39_PTE_PPN2_OFFSET)
			| PTE_V
	    	| PTE_R
			| PTE_W
			| PTE_G
			| PTE_A
			| PTE_D;

	/*
	 * Map virtual address QEMU_VIRT_START_PADDR + KBASE ~ QEMU_VIRT_START_PADDR + KBASE + 4G
	 * to physical address QEMU_VIRT_START_PADDR ~ QEMU_VIRT_START_PADDR + 4G.
	 */
	start_physical_page_num = PA2PPN1G(QEMU_VIRT_START_PADDR);
