{
        kfree(record->page);
        kfree(record);
}

int vmregion_record_cow_private_page(struct vmregion *vmr, vaddr_t vaddr,
                                     void *private_page)
{
        struct cow_private_page *record;

        record = kmalloc(sizeof(*record));
        if (!record)
