        memcpy(argv_text, pr->spawn.argv_text, PROC_REQ_TEXT_SIZE);
        memcpy(envp_text, pr->spawn.envp_text, PROC_REQ_ENV_TEXT_SIZE);

        for (int i = 0; i < input_argc; ++i) {
