static void thread_send_signal(struct thread *thread, int signum)
{
    lock(&thread->signal_lock);
    thread->pending_set |= (1UL << (signum-1));
    thread->TIF_SIGPENDING = thread->pending_set & ~thread->blocked_set;
    unlock(&thread->signal_lock);
}

