int sys_add_signal_handler(int signum, struct sigaction *act, struct sigaction *oldact)
{
    struct k_sigaction new_sa;
    struct k_sigaction *old_sa;

    if(signum < 0 || signum >= NSIG)
    {
        return -EINVAL;
    }

    if (act) {
        if (copy_from_user(&new_sa.sa, act, sizeof(new_sa.sa)))
            return -EFAULT;
    }


    lock(&current_thread->signal_lock);

    old_sa = &current_thread->sighand->action[signum-1];

    /* Perform Install */
    current_thread->sighand->action[signum-1] = new_sa; 
#if SIGDEBUG
    kinfo("sig action for %d is installed, new handler addr: 0x%lx\n", signum , current_thread->sighand->action[signum-1].sa.sa_handler);
#endif


    if (oldact) {
        if (copy_to_user(oldact, &old_sa->sa, sizeof(old_sa->sa))) {
            unlock(&current_thread->signal_lock);
            return -EFAULT;
        }
        // TODO: what about other field?
        oldact->sa_flags = 0;
        oldact->sa_mask = 0;
    }

    // missing SIG_IGN handling
    unlock(&current_thread->signal_lock);

#if SIGDEBUG
    kinfo("quit sys add signal handler\n");
#endif

    return 0;
}




