static void signal_timer_cb(struct thread *thread)
{
#if SIGDEBUG
    kinfo("into signal timercb\n");
#endif

    thread_send_signal(thread, SIGALRM); 

#if SIGDEBUG
    if (thread->TIF_SIGPENDING) {
        kinfo(" correct signaled, ret is 0x%lx\n", thread->thread_ctx->ec.reg[SEPC]);
    }
#endif
    return;
}

int sys_settimer(int which, int timeout_seconds)
{
#if SIGDEBUG
    kinfo("into sys settimer, timeout seconds: %d\n", timeout_seconds);
#endif
    struct timespec ts_k = {0};

    /* Init the ts_k */
    if (timeout_seconds != 0) {
        ts_k.tv_sec = timeout_seconds;
        ts_k.tv_nsec = 0;

        /* Because of timer exception is binded with CPU num
        * so we need to prevent this thread to be scheduled to other CPU
        */

        current_thread->thread_ctx->affinity = smp_get_cpu_id();
        lock(&current_thread->sleep_state.queue_lock);
        enqueue_sleeper(current_thread, &ts_k, signal_timer_cb);
        unlock(&current_thread->sleep_state.queue_lock);

#if SIGDEBUG
    kinfo("sys_timmer is set to %lx\n", signal_timer_cb);
#endif

    } else {
        // alarm(0) received, cancel previous timer
#ifdef SIGDEBUG
        kinfo("cancel timer\n");
#endif
        try_dequeue_sleeper(current_thread);
    }

    return 0;
}


