static int clone_thread_vmr(struct cap_group* parent_cap_group, struct cap_group* new_cap_group)
{
        struct vmspace* parent_vmspace, * new_vmspace;
        struct vmregion* vmr_tmp, * new_heap_vmr;
        struct pmobject* pmo_tmp, * new_pmo;
        cap_right_t rights;
        int ret = 0;

        parent_vmspace = obj_get(parent_cap_group, VMSPACE_OBJ_ID, TYPE_VMSPACE);
        new_vmspace = obj_get(new_cap_group, VMSPACE_OBJ_ID, TYPE_VMSPACE);
        BUG_ON(new_vmspace == NULL);

        /* Attention: there are some pmo in vmr but not in slot-table*/
        for_each_in_list(vmr_tmp, struct vmregion, list_node, &(parent_vmspace->vmr_list)) {
                /* Go to vmr list to find right vmr and copy it */
                rights = -1;
                for (unsigned int i = 0; i < parent_cap_group->slot_table.slots_size; ++i) {
                        if (parent_cap_group->slot_table.slots[i] == NULL ||
                                parent_cap_group->slot_table.slots[i]->object == NULL ||
                                parent_cap_group->slot_table.slots[i]->object->type != TYPE_PMO)
                                continue;
                        pmo_tmp = (struct pmobject*)parent_cap_group->slot_table.slots[i]->object->opaque;
                        if (vmr_tmp->pmo == pmo_tmp) {
                                rights = parent_cap_group->slot_table.slots[i]->rights;
                                break;
                        }
                }


                if (rights == -1) {
                        pmo_tmp = vmr_tmp->pmo;
                        rights = VMR_READ;
                }

                /* To simplify implementation, we don't register file to fs and just copy pmo directly */
                if (pmo_tmp->type == PMO_DATA) {
                        ret = create_pmo(pmo_tmp->size, pmo_tmp->type, new_cap_group,
                                0, &new_pmo, rights);
                        BUG_ON(ret < 0);
                        ret = vmspace_map_range(new_vmspace, vmr_tmp->start,
                                vmr_tmp->size, vmr_tmp->perm, new_pmo);
                        BUG_ON(ret < 0);
                        memcpy((void*)phys_to_virt(new_pmo->start), (void*)phys_to_virt(pmo_tmp->start), new_pmo->size);
                }
                else if (pmo_tmp->type == PMO_ANONYM) {
                        // if(vmr_tmp->perm & VMR_EXEC){
                        //         ret = vmspace_map_range(new_vmspace, vmr_tmp->start,
                        //                 vmr_tmp->size, vmr_tmp->perm, pmo_tmp);
                        //         if (ret < 0) {
                        //                 kinfo("vmspace map failed\n");
                        //         }
                        //         paddr_t parent_pmo_start;
                        //         int page_num = ROUND_UP(vmr_tmp->size, PAGE_SIZE) / PAGE_SIZE;
                        //         for (int i = 0; i < page_num; ++i) {
                        //                 vaddr_t va_itr = vmr_tmp->start + i * PAGE_SIZE;
                        //                 ret = query_in_pgtbl(parent_vmspace->pgtbl, va_itr, &parent_pmo_start, NULL);
                        //                 if (ret == 0) {
                        //                         // Alloc physics pages and put them into pmo
                        //                         map_range_in_pgtbl(new_vmspace->pgtbl, va_itr, parent_pmo_start, PAGE_SIZE, vmr_tmp->perm, NULL);
                        //                 }
                        //         }
                        // } else {
                        {
                                ret = create_pmo(pmo_tmp->size, pmo_tmp->type, new_cap_group,
                                        0, &new_pmo, rights);
                                BUG_ON(ret < 0);
                                ret = vmspace_map_range(new_vmspace, vmr_tmp->start,
                                        vmr_tmp->size, vmr_tmp->perm, new_pmo);
                                if (ret < 0) {
                                        kinfo("vmspace map failed\n");
                                }
                                paddr_t parent_pmo_start;
                                int page_num = ROUND_UP(vmr_tmp->size, PAGE_SIZE) / PAGE_SIZE;
                                for (int i = 0; i < page_num; ++i) {
                                        vaddr_t va_itr = vmr_tmp->start + i * PAGE_SIZE;
                                        ret = query_in_pgtbl(parent_vmspace->pgtbl, va_itr, &parent_pmo_start, NULL);
                                        if (ret == 0) {
                                                // Alloc physics pages and put them into pmo
                                                void* new_va = get_pages(0);
                                                BUG_ON(new_va == NULL);
                                                memcpy(new_va, (void*)phys_to_virt(parent_pmo_start), PAGE_SIZE);
                                                commit_page_to_pmo(new_pmo, i, virt_to_phys(new_va));
                                                map_range_in_pgtbl(new_vmspace->pgtbl, va_itr, virt_to_phys(new_va), PAGE_SIZE, vmr_tmp->perm, NULL);
                                        }
                                }
                        }

                }
                else if(pmo_tmp->type == PMO_SHM) {
                        // kinfo("Child share the PMO_SHM with parent\n");
                        ret = vmspace_map_range(new_vmspace, vmr_tmp->start,
                                vmr_tmp->size, vmr_tmp->perm, pmo_tmp);
                        if (ret < 0) {
                                kwarn("vmspace map PMO_SHM failed\n");
                        }
                } 
                else {
                        ret = create_pmo(pmo_tmp->size, pmo_tmp->type, new_cap_group,
                                0, &new_pmo, rights);
                        if(ret < 0 && pmo_tmp->type == PMO_FILE){
                                continue;
                        }
                        BUG_ON(ret < 0);
                        ret = vmspace_map_range(new_vmspace, vmr_tmp->start,
                                vmr_tmp->size, vmr_tmp->perm, new_pmo);
                        if (ret < 0) {
                                // kinfo("vmspace map failed\n");
                        }
                }
        }

        /* Get heap vmr and stack vmr */
        lock(&parent_vmspace->vmspace_lock);
        new_heap_vmr = find_vmr_for_va(new_vmspace, parent_vmspace->heap_boundary_vmr->start);
        BUG_ON(new_heap_vmr == NULL);
        unlock(&parent_vmspace->vmspace_lock);
        new_vmspace->heap_brk = parent_vmspace->heap_brk;
        new_vmspace->heap_boundary_vmr = new_heap_vmr;
        new_vmspace->rss = parent_vmspace->rss;

        obj_put(new_vmspace);
        obj_put(parent_vmspace);
        return 0;
}

