void arch_interrupt_init_per_cpu(void)
{
        /* Setup exception vector. */
        write_csr(stvec, exception_vector);

        /* Disable all interrupts in S mode. */
        clear_csr(sstatus, SSTATUS_SIE);

        /*
         * Enable Supervisor level interrupts, include
         * software, timer and external interrupt.
         */
        set_csr(sie, SIE_SEIE | SIE_SSIE | SIE_STIE);
}

void arch_interrupt_init(void)
{
        arch_interrupt_init_per_cpu();
        memset(irq_handle_type, HANDLE_KERNEL, MAX_IRQ_NUM);
}

void handle_async_irq_c(u64 scause)
{
        int r;
        u64 irqno;

        irqno = scause & (~SCAUSE_ASYN_IRQ);

        BUG_ON(irqno >= MAX_IRQ_NUM);
        if(irqno == SCAUSE_SUPERVISOR_EXTERNAL_IRQ){
                int irq = plic_claim();
                if(irq == VIRTIO0_IRQ){
                        kinfo("VIRTIO IRQ\n");
                        struct irq_notification *irq_notic;

                        irq_notic = irq_notifcs[61];
                        BUG_ON(!irq_notic);

                        // if (!irq_notic->user_handler_ready) {
                        //         kdebug("One interrupt (irq: %d) is ingored since the handler "
                        //         "thread is not ready.\n",
                        //         irq);
                        //         return 0;
                        // }

                        signal_irq_notific(irq_notic);
                }
                plic_complete(irq);
                return;
        }

        if (irq_handle_type[irqno] == HANDLE_USER) {
                r = user_handle_irq(irqno);
                BUG_ON(r);
                return;
        }

        switch (irqno) {
        case SCAUSE_SUPERVISOR_TIMER_IRQ:
                /* Supervisor timer interrupt */
                handle_timer_irq();
#ifdef CHCORE_SIGNAL
                exit_to_user_routine();
#endif
                sched_periodic();
                eret_to_thread(switch_context());
                BUG_ON("Should not reach here\n");
                break;

        case SCAUSE_SUPERVISOR_SOFT_IRQ:
                /* IPI */
                /* Clear the pending bit. */
                clear_csr(sip, SIP_SSIP);
                handle_ipi();
                break;

        default:
                BUG("Unsupported interrupt: %d, Instruction: 0x%lx, stval: 0x%lx\n",
                    irqno,
                    read_csr(sepc),
                    read_csr(stval));
        }
}

void handle_sync_exception_c(u64 scause, u64 sepc)
{
        /* Synchronous exception. */
        switch (scause) {
        case SCAUSE_INS_ILLEGAL:{
                kinfo("Illegal instruction, Instruction: 0x%lx, process dead!\n", sepc);
                kinfo("Current thread badge: %s\n", current_cap_group->badge);
                sys_exit_group(-1);
        }
        case SCAUSE_INS_PAGE_FAULT:
        case SCAUSE_LOAD_PAGE_FAULT:
        case SCAUSE_STORE_AMO_PAGE_FAULT:
                do_page_fault(scause, sepc);
                break;
        default:
                BUG("Unsupported exception: %d, Instruction: 0x%lx, Fault address: 0x%lx, process dead!\n",
                    scause,
                    sepc,
                    read_csr(stval));
        }
}

