#define USER_PTE 0
/*
 * the 3rd arg means the kind of PTE (user or kernel PTE)
 */
static int set_pte_flags(pte_t *entry, vmr_prop_t flags, int kind)
{
        /* Only consider USER PTE now. */
        BUG_ON(kind != USER_PTE);

        entry->pte.user = 1;

        if (flags & VMR_WRITE) {
                entry->pte.write = 1;
                entry->pte.read = 1;
                entry->pte.access = 1;
                entry->pte.dirty = 1;
        } else {
                entry->pte.write = 0;
                entry->pte.read = 1;
                entry->pte.access = 1;
        }

        if (flags & VMR_EXEC)
                entry->pte.exec = 1;
        else
                entry->pte.exec = 0;

        return 0;
}

#define NORMAL_PTP (0)
#define BLOCK_PTP  (1)

int get_next_ptp(ptp_t *cur_ptp, u32 level, vaddr_t va, ptp_t **next_ptp,
                 pte_t **pte, bool alloc, long *rss)
{
#if defined(SV48)
        u32 index;
        pte_t *entry;
        int ret;

        switch (level) {
        case 0:
                index = GET_L0_INDEX(va);
                break;
        case 1:
                index = GET_L1_INDEX(va);
                break;
        case 2:
                index = GET_L2_INDEX(va);
                break;
        case 3:
                index = GET_L3_INDEX(va);
                break;
        default:
                BUG("unexpected level\n");
                return -EINVAL;
        }

        entry = &(cur_ptp->ent[index]);

        if (!entry->pte.valid) {
                if (alloc == false) {
                        ret = -ENOMAPPING;
                        goto out;

                } else {
                        ptp_t *new_ptp;
                        pte_t new_pte_val;
                        paddr_t new_ptp_paddr;

                        new_ptp = get_pages(0);
                        BUG_ON(new_ptp == NULL);
                        memset(new_ptp, 0, PAGE_SIZE);
                        if (rss)
                                *rss += PAGE_SIZE;

                        new_ptp_paddr = virt_to_phys((void *)new_ptp);
                        new_pte_val.pte_val = 0;
                        new_pte_val.pte.valid = 1;
                        /* For QEMU versions 7.0.0 and above, U bit cannot be set for non-leaf PTE */
                        new_pte_val.pte_val |= (new_ptp_paddr >> PAGE_SHIFT)
                                               << 10;
                        entry->pte_val = new_pte_val.pte_val;
                }
        }

        *next_ptp = (ptp_t *)phys_to_virt(PTE2PA4K(entry->pte_val));
        *pte = entry;

        if (level == 3
            || !(entry->pte.read == 0 && entry->pte.write == 0
                 && entry->pte.exec == 0))
                ret = BLOCK_PTP;
        else
                ret = NORMAL_PTP;

out:
        return ret;
#elif defined(SV39)
	u32 index;
	pte_t *entry;
	int ret;

	switch (level){
		case 0:
			index = GET_L1_INDEX(va);
			break;
		case 1:
			index = GET_L2_INDEX(va);
			break;
		case 2:
			index = GET_L3_INDEX(va);
			break;
		default:
			BUG("unexpected level\n");
                        return -EINVAL;
	}
	entry = &(cur_ptp->ent[index]);

	if(!entry->pte.valid){
		if (alloc == false) {
			ret = -ENOMAPPING;
			goto out;
		} else {
                        ptp_t *new_ptp;
			paddr_t new_ptp_paddr;
			pte_t new_pte_val;

			new_ptp = get_pages(0);
			BUG_ON(new_ptp == NULL);
			memset(new_ptp, 0, PAGE_SIZE);
                        if (rss)
                                *rss += PAGE_SIZE;

			new_ptp_paddr = virt_to_phys((void*)new_ptp);
			new_pte_val.pte_val = 0;
			new_pte_val.pte.valid = 1;
			/* For QEMU versions 7.0.0 and above, U bit cannot be set for non-leaf PTE */
			new_pte_val.pte_val |= (new_ptp_paddr >> PAGE_SHIFT) << 10;
			entry->pte_val = new_pte_val.pte_val;
		}

	}
	*next_ptp = (ptp_t*)phys_to_virt(PTE2PA4K(entry->pte_val));
	*pte = entry;
	if(level == 2 || !(entry->pte.read == 0 && entry->pte.write == 0 && entry->pte.exec == 0)){
		ret = BLOCK_PTP;
	} else {
		ret = NORMAL_PTP;
	}
out:
	return ret;
#else
#error "SV32 not supported."
#endif

