/* Used to indicate current booting cpu's logical id. */
u32 cur_logical_cpuid = 0;

struct per_cpu_info cpu_info[PLAT_CPU_NUM] __attribute__((aligned(64)));

struct per_cpu_info *get_per_cpu_info(void)
{
	return (struct per_cpu_info *)read_csr(sscratch);
}

inline u32 smp_get_cpu_id(void)
{
	return get_per_cpu_info()->logical_cpuid;
}

void init_per_cpu_info(u32 hardware_cpuid)
{
	struct per_cpu_info *info;

	info = &cpu_info[cur_logical_cpuid];

	/* Save per_cpu_info in sscratch. */
	write_csr(sscratch, info);

	info->cur_exec_ctx = 0;

	info->cpu_stack = cpu_stacks[hardware_cpuid] + CPU_STACK_SIZE;

	/* fpu_owner and fpu_disable are not used in RISC-V. */
	info->fpu_owner = NULL;
	info->fpu_disable = 0;

	info->logical_cpuid = cur_logical_cpuid;
	info->hardware_cpuid = hardware_cpuid;

	info->t0 = 0;

	/* Mark this cpu as running to inform MP. */
	info->cpu_status = cpu_run;
}

void enable_smp_cores(void)
{
	u32 hardware_cpuid;

	for (hardware_cpuid = HART_BASE; hardware_cpuid < HART_BASE + PLAT_CPU_NUM; hardware_cpuid++) {
		if (hardware_cpuid != get_per_cpu_info()->hardware_cpuid) {
			cur_logical_cpuid++;
			sbi_hart_start(hardware_cpuid, virt_to_phys(&ap_start));
			while (cpu_info[cur_logical_cpuid].cpu_status != cpu_run);
			kinfo("[SMP] CPU %d is running\n", cur_logical_cpuid);
		}
	}

	init_ipi_data();
}

